fn try_decode_encrypted(data: &[u8]) -> Result<LlmPricingMetrics, String> {
    let pricing_offset = read_abi_offset(data, 1)?;
    let pricing_bytes = read_abi_bytes(data, pricing_offset)?;
    if pricing_bytes.is_empty() { return Err("Encrypted response has empty pricing data".to_string()); }
    let (model, prompt_tokens, completion_tokens) = decode_pricing_data(pricing_bytes)?;
}

pub fn decode_pricing_data(data: &[u8]) -> Result<(Option<String>, f64, f64), String> {
    if data.len() < 3 * 32 { return Err("pricing data too short".to_string()); }
    let model_offset = read_abi_offset(data, 0)?;
    let prompt_tokens = read_u256_as_f64(read_abi_word(data, 1)?)?;
    let completion_tokens = read_u256_as_f64(read_abi_word(data, 2)?)?;
    let model = non_empty_string(read_abi_string(data, model_offset)?);
}
